#!/usr/bin/env bash
# capture-pipeline.sh — 通用拍摄链 (Capture Pipeline) SOP walkthrough for 摄影.
# Auto-generated by cli_writer.py. Source: research/03-workflows.md.
set -euo pipefail
SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
source "${SCRIPT_DIR}/../lib/common.sh"

INDUSTRY="摄影"
WORKFLOW="通用拍摄链 (Capture Pipeline)"

usage() {
  cat <<EOF
capture-pipeline.sh — Walk through "${WORKFLOW}" SOP for ${INDUSTRY}

逐步走完这个工作流的入门 SOP, 然后做失败模式自检, 输出走查报告。

USAGE:
  ./capture-pipeline.sh             # interactive
  ./capture-pipeline.sh --dry-run
  ./capture-pipeline.sh --json
  ./capture-pipeline.sh --explain
  ./capture-pipeline.sh --help
EOF
}

explain() {
  cat <<'EOT'
这个 SOP 走查脚本帮你完成 "通用拍摄链 (Capture Pipeline)" 工作流。

一句话: 从「看到一个场景」到「按下快门得到一张曝光/对焦/构图都对的 RAW」的核心闭环——所有流派的地基。

入门 SOP 共 6 步, 失败模式自检 3 项。

相关心智模型:
  • 先问光，再问相机（光是主语，器材是宾语）: 摄影的第一性是「看光、控光、塑光」——画面好坏由光的方向/质感/光比决定，相机机身只是记录介质；资深人拿到任何场景先读光，外行先问「该买哪台相机」。
  • 成像前就决定成像（previsualization / 决定性瞬间）: 好照片在按快门之前就已在脑中成形——Adams 的「预想」(previsualization) 与 Cartier-Bresson 的「决定性瞬间」是同一直觉的两极：前者构建式预想最终影调，后者抓取式

来源: research/03-workflows.md.
EOT
}

DRY_RUN=0; JSON=0
for arg in "$@"; do
  case "$arg" in
    --help|-h) usage; exit 0 ;;
    --explain) explain; exit 0 ;;
    --dry-run) DRY_RUN=1 ;;
    --json) JSON=1 ;;
  esac
done

declare -a SOP_STEPS=(
  "**看光选光**: 判断光的方向/软硬/色温，决定拍不拍、从哪个角度拍、要不要等光。跳过 → 顺光大白光拍出平淡无立体的废片，后期救不回光质。(evidence: [T04-S007, T03-S024])"
  "**曝光三角决策**: 先定意图——光圈定景深（虚化/全景深）、快门定动静（凝固/拖影）、ISO 兜底补够曝光。跳过 → 该虚化的全清晰、该凝固的糊掉，曝光意图丢失。(evidence: [T03-S001])"
  "**测光与曝光**: 用评价测光起手，对高反差场景切点测光 + 看直方图确认高光不溢出（数字时代向右曝光 ETTR 提信噪比）。跳过 → 高光死白不可逆 / 暗部噪点重，宽容度浪费。(evidence: [T03-S002, T03-S003])"
  "**构图**: 三分法放主体、引导线/框架引视线、留负空间、安排前景层次。跳过 → 主体居中呆板、画面无引导、视觉重心散。(evidence: [T04-S006])"
  "**对焦**: 对主体（人像对眼）合焦，确认焦点不在背景。跳过 → 主体脱焦，整张作废。"
  "**拍摄 + 即时回看**: 按快门，必要时回放直方图/放大检查焦点。跳过即时回看 → 直到回家才发现整组脱焦/欠曝。"
)
declare -a FAILURE_MODES=(
  "**顺光平拍**: 不看光从正面大白光拍 → 强制先判断光向，逆/侧光或等黄金时刻。**CLI 自检**: 「你判断过光的方向和软硬了吗？还是举起就拍？」"
  "**高光溢出**: 没看直方图把高光拍死白 → 拍后扫一眼直方图右端，溢出就 -EV 重拍（高光死白后期不可逆，暗部还能拉）。**CLI 自检**: 「直方图右端贴墙了吗？高光救不回比暗部噪点严重得多。」"
  "**背景对焦**: 焦点落在主体后方 → 人像锁眼控 AF，静物用单点对主体。"
)
declare -a STEP_STATUS=()
declare -a STEP_NOTES=()
declare -a FAIL_CHECK=()

ms_section "${INDUSTRY} · ${WORKFLOW} 走查"
ms_info "逐步走完 ${#SOP_STEPS[@]} 步入门 SOP。每步可标 done / skipped / blocked。"
echo

for i in "${!SOP_STEPS[@]}"; do
  ms_section "Step $((i+1))/${#SOP_STEPS[@]}: ${SOP_STEPS[$i]}"
  ms_prompt "状态? [d=done / s=skipped / b=blocked]"
  read -r status
  STEP_STATUS+=("${status:-d}")
  case "${status:-d}" in
    s) ms_prompt "跳过原因 (一句话):"; read -r note ;;
    b) ms_prompt "blocker (一句话):"; read -r note ;;
    *) note="" ;;
  esac
  STEP_NOTES+=("$note")
done

if [[ ${#FAILURE_MODES[@]} -gt 0 ]]; then
  ms_section "失败模式自检"
  for fm in "${FAILURE_MODES[@]}"; do
    if ms_confirm "你是否避免了 — '$fm' ?"; then
      FAIL_CHECK+=("✓ $fm")
    else
      FAIL_CHECK+=("✗ $fm")
    fi
  done
fi

ms_buffer_append "# ${INDUSTRY} — ${WORKFLOW} 走查报告"
ms_buffer_append ""
ms_buffer_append "_生成时间: $(date '+%Y-%m-%d %H:%M:%S')_"
ms_buffer_append ""
ms_buffer_append "## SOP 步骤"
ms_buffer_append ""
for i in "${!SOP_STEPS[@]}"; do
  status_icon="?"
  case "${STEP_STATUS[$i]}" in
    d|D) status_icon="✓" ;;
    s|S) status_icon="↷" ;;
    b|B) status_icon="✗" ;;
  esac
  if [[ -n "${STEP_NOTES[$i]}" ]]; then
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]} — ${STEP_NOTES[$i]}"
  else
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]}"
  fi
done
ms_buffer_append ""
if [[ ${#FAIL_CHECK[@]} -gt 0 ]]; then
  ms_buffer_append "## 失败模式自检"
  ms_buffer_append ""
  for line in "${FAIL_CHECK[@]}"; do
    ms_buffer_append "- $line"
  done
  ms_buffer_append ""
fi

if [[ $JSON -eq 1 ]]; then
  ms_emit_json \
    "workflow" "${WORKFLOW}" \
    "step_count" "${#SOP_STEPS[@]}" \
    "failure_check_count" "${#FAILURE_MODES[@]}"
elif [[ $DRY_RUN -eq 1 ]]; then
  ms_emit_md_stdout
else
  ms_emit_md_file "capture-pipeline-walkthrough"
fi
